    def __init__(self):
        self.solutions = []
        self.best_solution = None
        self.best_performance = float('inf')

    def run(self, iterations=1000):
        for _ in range(iterations):
            solution = greedy_construction()
            for _ in range(10):  # Run low-level operators 10 times
                performance = np.sum([A[i][j] * x + B[i][j] * y + C[i][j] * z + D[i][j] * w for i, (x, y, z, w) in enumerate(solution)])
                if performance < self.best_performance:
                    self.best_solution = solution.copy()
                    self.best_performance = performance
                operator = choice_function(performance, _ % 2 == 0, len(self.solutions) % 3 == 0)
                if operator == 'greedy':
                    solution = greedy_construction()
