def simulate_annealing(x0, T_max, t_min_diff, alpha):
    x = x0.copy()
    T = T_max

    while T > t_min_diff:
        delta_E = -evaluate_objective(x)

        if delta_E < 0 or np.exp(-delta_E / T) > np.random.rand():
            new_x = np.random.normal(x, 0.1, size=len(x))
            new_x = new_x.clip(0, 1)  # ensure x's are in [0, 1]

            if evaluate_objective(new_x) < evaluate_objective(x):
                x = new_x
        else:
            x = new_x

        T *= alpha

    return x

def evaluate_objective(x):
    objective_value = 0

    for i in range(5):
        for j in range(4):
            if x[6*(i-1) + (j-1)] > 0.5:
                if j == 0:
                    objective_value += A[int(i)] * x[6*(i-1) + (j-1)]
                elif j == 1:
                    objective_value += B[int(i)] * x[6*(i-1) + (j-1)]
                elif j == 2:
                    objective_value += C[int(i)] * x[6*(i-1) + (j-1)]
                else:
                    objective_value += D[int(i)] * x[6*(i-1) + (j-1)]

    return -objective_value

def main():
    # Define the parameters
    A = [9, 4, 3, 7]
    B = [4, 6, 5, 6]
    C = [5, 4, 7, 5]
    D = [10, 6, 7, 4]

    # Initialize the population for the genetic algorithm
    x0 = np.array([1/5] * 20)

    # Set the simulation parameters
    T_max = 1000.0
    t_min_diff = 0.01
    alpha = 0.99

    # Run the simulated annealing algorithm
    optimal_x = simulate_annealing(x0, T_max, t_min_diff, alpha)

    # Evaluate the objective function at the optimal solution
    optimal_objective_value = -evaluate_objective(optimal_x)

    print(f"OBJECTIVE_VALUE: {optimal_objective_value:.2f}")

if __name__ == "__main__":
    main()

