def mutate_randomly(x):
    return x + np.random.randint(-1, 2, 4)

def crossover_by_average(x1, x2):
    return (x1 + x2) // 2

# Hyper-heuristic selection strategy
class SelectionHyperHeuristic:
    def __init__(self, operators):
        self.operators = operators
        self.weights = [0] * len(operators)

    def update_weights(self, objective_values):
        for i in range(len(objective_values)):
            self.weights[i] += (objective_values[i] - 11270) ** 2

    def choose_operator(self):
        return random.choice([op for _, op in sorted(zip(self.weights, self.operators))])

# Main solver
def solve_haus_toys():
    operators = [select_best, mutate_randomly, crossover_by_average]
    selection_hyper_heuristic = SelectionHyperHeuristic(operators)

    # Initial solution
    x0 = np.array([0] * 4)

    # Iteration loop
    for _ in range(100):
        x = x0.copy()

        # Apply operator
