        else:
            return choice_function_selection(operators, x)

    def reinforcement_learning_selection(self, operators, x):
        scores = []
        for op in operators:
            score = op.apply(x)
            if score > x:
                self.reinforcement_learning_rewards[operators.index(op)] += 1
            scores.append(score)
        probs = np.exp(np.array(scores)) / sum(np.exp(scores))
        return np.random.choice([x], p=probs)[0]

    def choice_function_selection(self, operators, x):
        recency = [1 - i/len(operators) for i in range(len(operators))]
        improvement = [(score - x) for score in self.reinforcement_learning_rewards]
        diversity = [np.std([op.apply(x) for op in operators])]
        return np.random.choice([x], weights=np.array(recency + improvement + diversity), p=None)[0]

def roulette_wheel_selection(operators, x):
    scores = []
    for op in operators:
        score = op.apply(x)
        if score > x:
            scores.append(score)
        else:
            scores.append(0)

    probs = np.exp(np.array(scores)) / sum(np.exp(scores))
