import numpy as np
from scipy.optimize import minimize

# Problem constants
LABOR_PER_UNIT = [3, 2, 6]
MATERIAL_PER_UNIT = [4, 3, 6]
SELLING_PRICE = [120, 80, 180]
VARIABLE_COST = [60, 40, 80]
AVAILABLE_LABOR = 1500
AVAILABLE_MATERIAL = 1600
FIXED_COSTS = [2000, 1500, 1000]

# Hyper-heuristic parameters
MAX_ITERATIONS = 500
POPULATION_SIZE = 20

class LowLevelOperator:
    def __init__(self):
        self.type = "unknown"

    def apply(self, solution):
        raise NotImplementedError()

class Mutation(LowLevelOperator):
    def apply(self, solution):
        # Randomly change one variable
        idx = np.random.randint(0, len(solution))
        new_value = np.random.uniform(-100, 100)
        if idx == 0:
            return [new_value] + solution[1:]
        elif idx == 1:
            return solution[0] + [new_value]
        else:
            return solution[0] + solution[1] + [new_value]

class Crossover(LowLevelOperator):
    def apply(self, solution):
        # Randomly select two parents and perform crossover
        parent1_idx = np.random.randint(0, len(solution))
        parent2_idx = np.random.randint(0, len(solution))
        while parent1_idx == parent2_idx:
            parent2_idx = np.random.randint(0, len(solution))

        parent1 = solution[parent1_idx]
        parent2 = solution[parent2_idx]

        child = []
        for i in range(len(parent1)):
            if i % 2 == 0:
                child.append(parent1[i])
            else:
                child.append(parent2[i])

        return child

class Selection(LowLevelOperator):
    def apply(self, solution):
        # Randomly select a variable to increment
        idx = np.random.randint(0, len(solution))
        new_value = round(solution[idx] + np.random.uniform(-1, 1), 4)
        if new_value < 0:
            return [max(new_value, 0)] + solution[1:]
        else:
            return solution[0] + [new_value]

class HyperHeuristic:
    def __init__(self):
        self.operators = [Mutation(), Crossover(), Selection]
        self.weights = [1/3, 1/3, 1/3]
        self.performance_history = []

    def adapt_weights(self, performance):
        # Update weights based on performance
        for i in range(len(self.operators)):
            if performance > 0:
                self.weights[i] += (performance - 1) / len(self.operators)
            else:
                self.weights[i] -= (abs(performance) + 1) / len(self.operators)

    def choose_operator(self):
        # Use roulette-wheel selection with weights
        return np.random.choice(self.operators, p=self.weights/sum(self.weights))

    def solve(self, initial_solution):
        best_solution = initial_solution
        for _ in range(MAX_ITERATIONS):
            operator = self.choose_operator()
            new_solution = operator.apply(best_solution)
            performance = self.evaluate(new_solution)

            if performance > self.evaluate(best_solution):
                best_solution = new_solution

            self.performance_history.append(performance)

        return best_solution

    def evaluate(self, solution):
        # Calculate the objective value
        revenue = sum([p * s for p, s in zip(SELLING_PRICE, solution)])
        cost = sum([v * s for v, s in zip(VARIABLE_COST, solution)]) + sum(FIXED_COSTS)
        return revenue - cost

# Main solver
def solve_hyper_heuristic():
    # Initialize the hyper-heuristic and problem data
    hyper_heuristic = HyperHeuristic()
    initial_solution = [0.5, 1.2, 3.5]  # Rough reference point from heuristic (use with caution)

    best_solution = hyper_heuristic.solve(initial_solution)
    objective_value = hyper_heuristic.evaluate(best_solution)

    print(f"OBJECTIVE_VALUE: {objective_value:.4f}")

