# Problem parameters
Q_A, Q_B, Q_C, Q_D, Q_E = 120, 90, 300, 90, 120
W_A, W_B, W_C, W_D, W_E = 0.5, 1, 0.4, 0.6, 0.65

# Low-level operators (heuristics)
def mutate_solution(solution):
    # Randomly swap two goods in the solution
    i, j = random.sample(range(len(solution)), 2)
    solution[i], solution[j] = solution[j], solution[i]
    return solution

def crossover_operator(parent1, parent2):
    # Simple crossover: take first half from each parent
    child = []
    for i in range(len(parent1) // 2):
        if random.random() < 0.5:
            child.append(parent1[i])
        else:
            child.append(parent2[i])
    return child

def selection_operator(solution, f):
    # Select the best solution based on the objective function
    return np.argmin(f(np.array([solution])))

# Hyper-heuristic framework
class AdaptiveSelector:
    def __init__(self):
        self.operator_weights = [0.25, 0.25, 0.5]
        self.operator_history = []
        self.best_solution = None

    def select_operator(self, f):
        # Roulette-wheel selection with performance-based weights
        if random.random() < 0.2:
            return np.argmax([f(mutate_solution(self.best_solution)) for _ in range(len(self.operator_weights))])
        elif random.random() < 0.5:
            return self.operator_history.index(min(self.operator_history))
        else:
            return np.argmin([f(crossover_operator(self.best_solution, self.best_solution))])

    def update(self, f):
        # Update the operator weights and history based on performance
        best_so_far = np.min(f(np.array([[i] for i in range(Q_A + Q_B + Q_C + Q_D + Q_E)])))
        if f(np.array([self.best_solution])) < best_so_far:
            self.operator_weights[0] += 0.1
            self.operator_weights[1] -= 0.05
            self.operator_history.append(f(self.best_solution))
        else:
            for i in range(len(self.operator_weights)):
                self.operator_weights[i] -= 0.01

    def run(self, f):
        # Run the adaptive selector for a specified number of iterations
        for _ in range(100):
            operator_index = self.select_operator(f)
            if operator_index == 0:
                self.best_solution = mutate_solution(self.best_solution)
            elif operator_index == 1:
                crossover_child = crossover_operator(self.best_solution, self.best_solution)
                if f(np.array([crossover_child])) < f(np.array([self.best_solution])):
                    self.best_solution = crossover_child
            self.update(f)
        return self.best_solution

# Define the objective function and initial solution
def objective_function(solution):
    # Calculate the total weight of the goods in the container
    return -sum(W_A * (Q_A - sum(i <= Q_A for i in solution)) +
                W_B * (Q_B - sum(i <= Q_B for i in solution)) +
                W_C * (Q_C - sum(i <= Q_C for i in solution)) +
                W_D * (Q_D - sum(i <= Q_D for i in solution)) +
                W_E * (Q_E - sum(i <= Q_E for i in solution)))

best_solution = AdaptiveSelector().run(objective_function)

# Print the result
print(f"OBJECTIVE_VALUE: {objective_function(best_solution)}")

