    def __init__(self):
        pass

    def apply(self, solution1, solution2):
        crossover_point = random.randint(1, len(solution1) - 1)
        new_solution1 = solution1[:crossover_point] + [1 - x for x in solution2[crossover_point:]]
        new_solution2 = solution2[:crossover_point] + [1 - x for x in solution1[crossover_point:]]
        return [new_solution1, new_solution2]


