    # Select the best trip based on pollution reduction
    return -x * (horse_pollution_per_trip + bicycle_handcart_pollution_per_trip) / total_produce_to_transport

def swap_two_items(x, y):
    # Swap two trips between horse and bicycle/handcart
    x_horse = np.floor_divide(x, 80)
    x_bicycle_handcart = total_produce_to_transport - x_horse * 80
    if (x_horse > 8) and (y < produce_per_bicycle_handcart_trip):
        return x + y, "bicycle"
    elif (x_bicycle_handcart > 20) and (y > produce_per_handcart_trip):
        return x - y, "handcart"
    else:
        return x, "horse"

# Define hyper-heuristic
def hyper_heuristic(x0, iterations=1000):
    # Initialize population size and operator selection probability
    N = 5
    p_selection = 0.8

    # Initialize best solution
    best_solution = {"horse_trips": 8, "bicycle_trips": 20, "handcart_trips": 40}
    best_value = np.inf

    for _ in range(iterations):
        # Select operators based on performance
        if np.random.rand() < p_selection:
            operator = select_best(x0["horse_trips"])
        else:
            operator = swap_two_items(x0["horse_trips"], 100 - x0["horse_trips"])

        # Apply selected operator
        if operator[1] == "bicycle":
