        else:
            x1 = {"horse_trips": 8 + np.random.randint(5)}

        # Evaluate new solution
        value = evaluate_solution(x1)

        # Update best solution if needed
        if value < best_value:
            best_solution = x1
            best_value = value

        # Update population with new solution
        x0["horse_trips"] = x1["horse_trips"]
        x0["bicycle_trips"] = x1.get("bicycle_trips", 20)
        x0["handcart_trips"] = x1.get("handcart_trips", 40)

    return best_solution, best_value

