    def apply(self, x):
        for i, j in self.permutations:
            if np.all(x[[i, j]] == [0, 1]):
                x[[i, j]] = [1, 0]
        return x

class OrOpt:
    def __init__(self):
        self.candidates = [(x11, x12), (x21, x22)]

    def apply(self, x):
        for i, candidate in enumerate(self.candidates):
            if all(candidate) and not np.all(x[i:i+2]):
                x[i:i+2] = [1, 0]
        return x

# Selection hyper-heuristic
class AdaptiveSelector:
    def __init__(self):
        self.weights = [0.5, 0.5]

    def roulette_wheel_selection(self, operators, x):
        total_cost = sum([total_transportation_cost(apply_operator(x)) for apply_operator in operators])
        return choice(operators)(x)

    def reinforcement_learning_selection(self, operators, x):
        rewards = []
        for operator in operators:
            new_x = operator(x)
            cost = total_transportation_cost(new_x) + penalty_function(new_x)
            rewards.append(cost if cost < total_transportation_cost(x) else -cost)
        return operators[np.argmax(rewards)]

    def choice_function_selection(self, operators, x):
        recency_weight = 0.3
        improvement_weight = 0.4
        diversity_weight = 0.3

        operator_costs = []
        for operator in operators:
            new_x = operator(x)
            cost = total_transportation_cost(new_x) + penalty_function(new_x)
            operator_costs.append((cost, recency_weight * x.sum(), diversity_weight * (1 - np.count_nonzero(x)) / n))
        return min(operator_costs, key=lambda x: x[0] + recency_weight * x[1] + diversity_weight * x[2])

    def select_operator(self, operators, x):
        if random.randint(0, 1) == 0:
            return self.roulette_wheel_selection(operators, x)
        elif random.random() < 0.5:
            return self.reinforcement_learning_selection(operators, x)
        else:
            return self.choice_function_selection(operators, x)

# Main solver
def hyper_heuristic_solver():
    operators = [TwoOpt(), OrOpt()]
    selector = AdaptiveSelector()
    x = np.zeros(n**2, dtype=bool)
    best_cost = float('inf')

    for _ in range(1000):  # Run for a configurable number of iterations
        operator = selector.select_operator(operators, x)
        x = operator.apply(x)
        cost = total_transportation_cost(x) + penalty_function(x)

        if cost < best_cost:
            best_cost = cost
            print(f"OBJECTIVE_VALUE: {best_cost:.2f}")

    return best_cost

