import numpy as np
from scipy.optimize import minimize

class FurnitureFactorySolver:
    def __init__(self, num_iterations=1000):
        self.num_iterations = num_iterations
        self._operators = [
            {"name": "greedy_tables", "func": self.greedy_tables},
            {"name": "local_search_chairs", "func": self.local_search_chairs},
            {"name": "perturb_bookshelves", "func": self.perturb_bookshelves},
            {"name": "crossover_repair", "func": self.crossover_repair}
        ]
        self.selection_hyperheuristic = "roulette"

    def greedy_tables(self, x):
        # Construct tables first
        t = min(int(x[0] * 200 / 120), 20)
        return {"T": t, "C": 0, "B": 0}

    def local_search_chairs(self, x):
        # Search for chairs
        c = min(int(x[1] * 50 / 20), 10)
        return {"T": int(x[2]), "C": c, "B": 0}

    def perturb_bookshelves(self, x):
        # Perturb bookshelves
        b = np.random.randint(0, 11)  # Bookshelves between 0 and 20
        return {"T": int(x[3]), "C": int(x[4]), "B": b}

    def crossover_repair(self, x):
        # Crossover repair
        t, c, b = int(x[5]), int(x[6]), int(x[7])
        if (t + c + b) > 200:
            # Repair by reducing tables and chairs
            t -= (t + c + b - 200)
            return {"T": t, "C": c, "B": b}
        else:
            return {"T": t, "C": c, "B": b}

    def roulette(self, x):
        # Roulette wheel selection
        total_value = sum([op["value"] for op in self.get_operator_values(x)])
        weights = [value / total_value for value in self.get_operator_values(x)]
        operator_index = np.random.choice(len(self._operators), p=weights)
        return self._operators[operator_index]["func"](x)

    def get_operator_values(self, x):
        values = []
        for op in self._operators:
            y = op["func"](x)
            profit = self.calculate_profit(y)
            values.append(profit)
        return values

    def calculate_profit(self, y):
        # Calculate profit using the given mathematical formulation
        t, c, b = y["T"], y["C"], y["B"]
        table_cost = 120 * t
        chair_cost = 20 * c
        bookshelf_cost = 90 * b
        total_cost = table_cost + chair_cost + bookshelf_cost
        profit = (200 * t) + (50 * c) + (150 * b) - total_cost
        return profit

    def solve(self):
        x0 = {"T": 10, "C": 20, "B": 20}
        res = minimize(self.roulette, np.array(list(x0.values())), method="SLSQP", options={"maxiter": self.num_iterations})
        print(f"OBJECTIVE_VALUE: {res.fun}")

