                scores.append(score)
            return np.random.choice(self.operators, p=[s / sum(scores) for s in scores])

        def adapt_weights(self):
            for op in self.operators:
                if op.__class__.__name__ == 'GreedyConstruction':
                    self.weights[0] += 0.1
                elif op.__class__.__name__ == 'LocalSearchSwap':
                    self.weights[1] += 0.2
                else:
                    self.weights[2] += 0.3

        def run(self, max_iter=100):
