class Mutation(Operator):
    def apply(self, x):
        new_x = np.copy(x)
        for i in range(len(new_x)):
            if random.random() < 0.1:
                new_x[i] += random.uniform(-5, 5)
        return new_x

class Crossover(Operator):
    def apply(self, x):
        new_x = np.zeros_like(x)
        for i in range(int(len(x) / 2)):
            new_x[2 * i] = x[2 * i]
            new_x[2 * i + 1] = x[2 * i + 1]
        return new_x

class Selection(Operator):
    def apply(self, x):
        return np.array([max(x[0], 0), max(x[1], 0)])

# Define the selection hyper-heuristic
class HyperHeuristic:
    def __init__(self):
        self.operators = [Mutation("mutation"), Crossover("crossover"), Selection("selection")]
        self.weights = np.ones(len(self.operators)) / len(self.operators)

    def get_operator(self, x):
        if random.random() < 0.5:
            return random.choice([o for o in self.operators if isinstance(o, Mutation)])
        elif random.random() < 0.8:
            return random.choice([o for o in self.operators if isinstance(o, Crossover)])
        else:
