import numpy as np

def solve_danzig_street_parking():
    lambda_values = [4, 4.5, 5, 4.1, 2.4, 5.2, 3.7, 3.5, 3.2, 4.5, 2.3, 3.3, 3.8, 4.6, 3]
    street_length = 60  # meters

    def heuristic_binary_search():
        low = sum(lambda_values)
        high = street_length
        best_solution = None
        best_value = float('inf')

        while low <= high:
            mid = (low + high) / 2.0
            left_side_length, right_side_length = binary_search_split_parking(mid)

            if left_side_length + right_side_length <= street_length and left_side_length >= sum(lambda_values):
                if left_side_length + right_side_length < best_value:
                    best_solution = (left_side_length, right_side_length)
                    best_value = left_side_length + right_side_length

            low = mid
        return best_solution, best_value

    def binary_search_split_parking(mid):
        left_side_length = 0
        for lambda_i in lambda_values:
            if left_side_length + lambda_i <= mid:
                left_side_length += lambda_i
            else:
                right_side_length = min(mid - left_side_length, sum(lambda_values) - left_side_length)
                return left_side_length, right_side_length

        return 0, street_length - max(lambda_values)

    best_solution, best_value = heuristic_binary_search()
    print(f"OBJECTIVE_VALUE: {best_value}")

