# Problem parameters
p_A = 30
p_B = 10
hr_per_A = 6
hr_per_B = 3
max_hours = 40
min_product_A = 0
max_product_A = 4
min_product_B = 0
max_product_B = float('inf')

# Low-level operators
class GreedyConstruction:
    def __init__(self):
        pass

    def apply(self, variables):
        A = min(max(variables[0] + (max_hours - 6 * variables[0]) / hr_per_A, 0), max_product_A)
        B = max(min((3 * A) + ((40 - 6 * A) / 3), max_product_B), min_product_B)
        return [A, B]

class LocalSearchSwap:
    def __init__(self):
        pass

    def apply(self, variables):
        A = variables[0]
        B = variables[1]
        delta_A = random.uniform(-1, 1) * min(max_hours - 6 * A, max_product_A)
        delta_B = random.uniform(-1, 1) * (max_product_B - max(3 * A, min_product_B))
        new_A = max(min(A + delta_A, max_product_A), min_product_A)
        new_B = max(min(B + delta_B, max_product_B), min_product_B)
        return [new_A, new_B]

class Perturbation:
    def __init__(self):
        pass

    def apply(self, variables):
        A = variables[0]
        B = variables[1]
        delta_A = random.uniform(-1, 1) * min(max_hours - 6 * A, max_product_A)
        delta_B = random.uniform(-1, 1) * (max_product_B - max(3 * A, min_product_B))
        return [A + delta_A, B + delta_B]

# Selection hyper-heuristic
class AdaptiveSelection:
    def __init__(self):
        self.operator_weights = np.array([0.5, 0.5])

    def select_operator(self, variables, best_score):
        if random.random() < self.operator_weights[0]:
            return GreedyConstruction()
        elif random.random() < (self.operator_weights[0] + self.operator_weights[1]):
            return LocalSearchSwap()
        else:
            return Perturbation()

def objective_function(variables):
    A = variables[0]
    B = variables[1]
    return p_A * A + p_B * B

def constraint_function(variables):
    A = variables[0]
    B = variables[1]
    return [6 * A + 3 * B - max_hours, (B - 3 * A) / 3]

def main():
    adaptive_selection = AdaptiveSelection()
    best_score = float('-inf')
    for _ in range(100):
        variables = np.array([random.uniform(min_product_A, max_product_A), random.uniform(min_product_B, max_product_B)])
        while True:
            operator = adaptive_selection.select_operator(variables, best_score)
            variables = operator.apply(variables)
            if constraint_function(variables)[0] < 0 and constraint_function(variables)[1] > 0:
                break
        score = objective_function(variables)
        if score > best_score:
            best_score = score
    print("OBJECTIVE_VALUE:", best_score)

if __name__ == "__main__":
    main()

