import numpy as np
from scipy.optimize import minimize
import math

# Define the objective function to be minimized
def rental_cost(bus_count, minibus_count):
    return 800 * bus_count + 600 * minibus_count

# Define the constraint functions
def student_capacity_constraint(bus_count, minibus_count):
    return 50 * bus_count + 40 * minibus_count - 400

def driver_availability_constraint(bus_count, minibus_count):
    return bus_count + minibus_count - 9

def bus_capacity_constraint(bus_count):
    return (50 - bus_count)

def minibus_capacity_constraint(minibus_count):
    return (40 - minibus_count)

# Define the penalty function for constraint violation
def penalty_function(x):
    penalty = 0
    if student_capacity_constraint(*x) > 1e-6:
        penalty += abs(student_capacity_constraint(*x))
    if driver_availability_constraint(*x) > 1e-6:
        penalty += abs(driver_availability_constraint(*x))
    if bus_capacity_constraint(x[0]) < -1e-6:
        penalty += abs(bus_capacity_constraint(x[0]))
    if minibus_capacity_constraint(x[1]) < -1e-6:
        penalty += abs(minibus_capacity_constraint(x[1]))
    return penalty

# Define the Simulated Annealing algorithm
def simulated_annealing():
    # Initialize the parameters
    T = 10000.0
    alpha = 0.95
    x0 = np.array([5, 2])  # Initial guess for bus and minibus counts

    # Run the annealing process
    best_x = x0.copy()
    best_fitness = rental_cost(*x0) + penalty_function(x0)
    while T > 1e-6:
        # Generate a new solution by perturbing the current one
        x_new = x0 + np.random.uniform(-1, 1, 2)

        # Calculate the fitness of the new solution
        fitness = rental_cost(*x_new) + penalty_function(x_new)

        # Accept or reject the new solution based on the annealing schedule
        delta_fitness = fitness - best_fitness
        if delta_fitness < 0:
            x0 = x_new.copy()
            best_fitness = fitness
        else:
            r = math.exp(delta_fitness / T)
            if np.random.rand() < r:
                x0 = x_new.copy()

        # Decrease the temperature
        T *= alpha

    return best_x, best_fitness

# Run the simulated annealing algorithm and print the result
best_x, best_fitness = simulated_annealing()
print(f"OBJECTIVE_VALUE: {best_fitness}")

