import numpy as np
from scipy.optimize import minimize
import matplotlib.pyplot as plt

# Define the parameters, constraints, and objective function
def objective(x):
    cost_per_1000_boxes_week1 = 5.0
    cost_per_1000_boxes_week2 = 5.1
    cost_per_1000_boxes_week3 = 5.4
    cost_per_1000_boxes_week4 = 5.5
    storage_cost_per_week_per_thousand_boxes = 0.2

    total_cost = (cost_per_1000_boxes_week1 * x[0]) + (cost_per_1000_boxes_week2 * x[1]) + (cost_per_1000_boxes_week3 * x[2]) + (cost_per_1000_boxes_week4 * x[3]) + ((x[0] - 15) * (x[1] - 25) * (x[2] - 35) * (x[3] - 25) * storage_cost_per_week_per_thousand_boxes)

    return total_cost

def constraint1(x):
    demand_for_each_week = np.array([15, 25, 35, 25])
    return x - demand_for_each_week

def constraint2(x):
    production_capacity = np.array([30, 40, 45, 20])
    return production_capacity - x

def constraint3(x):
    total_production = sum(x)
    total_capacity = 135
    return total_capacity - total_production

# Define the low-level operators
class Mutation:
    def __init__(self, sigma=0.1):
        self.sigma = sigma

    def apply(self, x):
        return x + np.random.normal(0, self.sigma, len(x))

class Crossover:
    def __init__(self, crossover_rate=0.5):
        self.crossover_rate = crossover_rate

    def apply(self, x1, x2):
        mask = np.random.binomial(1, self.crossover_rate, len(x1))
        return x1 * mask + x2 * (1 - mask)

class Selection:
    def __init__(self, performance_weights=None, reward_function=None):
        if performance_weights is None:
            self.performance_weights = [1.0] * 4
        else:
            self.performance_weights = performance_weights

        if reward_function is None:
            self.reward_function = lambda x: np.sum(x)
        else:
            self.reward_function = reward_function

    def apply(self, parent, child):
        parent_performance = self.reward_function(parent)
        child_performance = self.reward_function(child)

        total_performance = sum([self.performance_weights[i] * (child[i] if i in range(len(parent)) and child[i] > parent[i] else 0) for i in range(len(child))])

        if total_performance > parent_performance:
            return child
        else:
            return parent

# Define the hyper-heuristic
class HyperHeuristic:
    def __init__(self, low_level_operators=[Mutation(), Crossover()], selection_strategy=Selection()):
        self.low_level_operators = low_level_operators
        self.selection_strategy = selection_strategy

    def run(self):
        x0 = np.array([15, 25, 35, 25])  # Initialize with the demand values

        for _ in range(100):  # Run for a configurable number of iterations
            parent = minimize(objective, x0, method="SLSQP", constraints=({"type": "ineq", "fun": lambda x: constraint1(x)}, {"type": "ineq", "fun": lambda x: constraint2(x)}, {"type": "ineq", "fun": lambda x: constraint3(x)})).x
            child = self.selection_strategy.apply(parent, min(self.low_level_operators, key=lambda op: np.max(np.abs(op.apply(parent) - parent)), default=self.low_level_operators[0]).apply(parent))
            x0 = child  # Update the current solution

        return x0

# Run the hyper-heuristic
hyper_heuristic = HyperHeuristic()
result = hyper_heuristic.run()

print(f"OBJECTIVE_VALUE: {objective(result)[0]}")

import numpy as np
from scipy.optimize import minimize

# Define parameters
total_raw_pipes = 1850 // 290 + 1850 // 315 + 1850 // 350 + 1850 // 455
extra_cost_per_pattern = [1/10, 2/10, 3/10]

# Define low-level operators
def first_fit(x):
    return np.sum(x * (np.arange(len(x)) % len(extra_cost_per_pattern)))

def best_fit(x):
    return np.max(x) * max(extra_cost_per_pattern)

def worst_fit(x):
    return np.min(x) * min(extra_cost_per_pattern)

# Define selection hyper-heuristic
def select_operator(current_solution, x):
    # Roulette-wheel selection with performance-based weights
    weights = [first_fit(current_solution), best_fit(current_solution), worst_fit(current_solution)]
    operator_idx = np.random.choice([0, 1, 2], p=weights / sum(weights))

    if operator_idx == 0:
        return first_fit(x)
    elif operator_idx == 1:
        return best_fit(x)
    else:
        return worst_fit(x)

# Define objective function
def objective(x):
    # Calculate total cost based on x and extra_cost_per_pattern
    return np.sum(x * (np.arange(len(x)) % len(extra_cost_per_pattern)))

# Initialize solution and bounds
